import os
import sys
import tarfile
from zipfile import ZipFile
from py7zr import SevenZipFile

def make_tarball(source_dir, output):
    with tarfile.open(output, "w:gz") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))
        
def make_bz2ball(source_dir, output):
    with tarfile.open(output, "w:bz2") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))
        
def make_zipball(source_dir, output):
    with ZipFile(output, 'w') as zipf:
        for root, dirs, files in os.walk(source_dir):
            for file in files:
                zipf.write(os.path.join(root, file))
                
def make_7zball(source_dir, output):
    with SevenZipFile(output, 'w') as zf:
        zf.write(source_dir)
        
def backup(directory, format):
    if not os.path.exists(directory):
        print("Error: Directory does not exist.")
        sys.exit(-1)
    
    output = f"{directory}.{format}"
    
    functions = {
        'tar.gz': make_tarball,
        'tar.bz2': make_bz2ball,
        'zip': make_zipball,
        '7z': make_7zball
    }

    if format not in functions:
        print("Error: Unsupported archive format.")
        sys.exit(-1)
        
    print(f"Creating backup of {directory} as {output}...")
    functions[format](directory, output)
    print("Backup created successfully!")